use serde::Serialize;

/// A name candidate generated by one or more LLMs.
#[derive(Debug, Clone, Serialize)]
pub struct NameCandidate {
    pub name: String,
    pub suggested_by: Vec<String>,
}

/// Compact domain availability summary.
#[derive(Debug, Clone, Serialize)]
pub struct DomainSummary {
    pub available: usize,
    pub registered: usize,
    pub unknown: usize,
    pub total: usize,
    pub details: Vec<DomainDetail>,
}

#[derive(Debug, Clone, Serialize)]
pub struct DomainDetail {
    pub domain: String,
    pub available: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub site: Option<String>,
}

/// Compact package registry availability summary.
#[derive(Debug, Clone, Serialize)]
pub struct PackageSummary {
    pub available: usize,
    pub taken: usize,
    pub unknown: usize,
    pub total: usize,
    pub details: Vec<PackageDetail>,
}

#[derive(Debug, Clone, Serialize)]
pub struct PackageDetail {
    pub registry: String,
    pub available: String,
}

/// Compact app store availability summary.
#[derive(Debug, Clone, Serialize)]
pub struct StoreSummary {
    pub available: usize,
    pub taken: usize,
    pub unknown: usize,
    pub total: usize,
    pub details: Vec<StoreDetail>,
}

#[derive(Debug, Clone, Serialize)]
pub struct StoreDetail {
    pub store: String,
    pub available: String,
    pub similar_count: usize,
}

/// A fully-checked name with score and availability details.
#[derive(Debug, Clone, Serialize)]
pub struct NameResult {
    pub name: String,
    pub score: f64,
    pub suggested_by: Vec<String>,
    pub domains: DomainSummary,
    pub packages: PackageSummary,
    pub stores: StoreSummary,
}

/// The full output of a find_names or check_names operation.
#[derive(Debug, Clone, Serialize)]
pub struct AvailableResult {
    pub results: Vec<NameResult>,
    pub models_used: Vec<String>,
    pub errors: Vec<GenerationError>,
}

/// Records a per-model generation failure.
#[derive(Debug, Clone, Serialize)]
pub struct GenerationError {
    pub model: String,
    pub error: String,
}

/// Configuration for name generation and checking.
#[derive(Debug, Clone)]
pub struct Config {
    pub tlds: Vec<String>,
    pub registry_ids: Vec<String>,
    pub all_registries: bool,
    pub languages: Vec<String>,
    pub store_ids: Vec<String>,
    pub max_names: usize,
}

impl Default for Config {
    fn default() -> Self {
        Self {
            tlds: vec!["com".into(), "dev".into(), "io".into(), "app".into()],
            registry_ids: vec![],
            all_registries: false,
            languages: vec![],
            store_ids: vec![],
            max_names: 20,
        }
    }
}
